class Solution {
    public long findMaximumNumber(long k, int x) {
        long num = 0;
        long accumulatedPrice = 0;
        while (true) {
            long price = getPrice(num, x);
            if (accumulatedPrice + price > k) {
                break;
            }
            accumulatedPrice += price;
            num++;
        }
        return num - 1;
    }

    private long getPrice(long num, int x) {
        long price = 0;
        long multiplier = 1;
        while (num > 0) {
            if ((num & 1) == 1) {
                price += multiplier;
            }
            num >>= 1;
            multiplier *= x;
        }
        return price;
    }
}
```
